174Ôćĺexport const GuildEventCode = {
175Ôćĺ  PROMOTION: 0,
176Ôćĺ  DEMOTION: 1,
177Ôćĺ  MOTD: 2,
178Ôćĺ  JOINED: 3,
179Ôćĺ  LEFT: 4,
180Ôćĺ  REMOVED: 5,
181Ôćĺ  LEADER_IS: 6,
182Ôćĺ  LEADER_CHANGED: 7,
183Ôćĺ  DISBANDED: 8,
184Ôćĺ  SIGNED_ON: 12,
185Ôćĺ  SIGNED_OFF: 13,
186Ôćĺ} as const;
187Ôćĺ
188Ôćĺconst HAS_TRAILING_GUID = new Set([
189Ôćĺ  GuildEventCode.JOINED,
190Ôćĺ  GuildEventCode.LEFT,
191Ôćĺ  GuildEventCode.SIGNED_ON,
192Ôćĺ  GuildEventCode.SIGNED_OFF,
193Ôćĺ]);
194Ôćĺ
195Ôćĺexport type GuildEventRaw = {
196Ôćĺ  eventType: number;
197Ôćĺ  params: string[];
198Ôćĺ};
199Ôćĺ
200Ôćĺexport function parseGuildEvent(r: PacketReader): GuildEventRaw {
201Ôćĺ  const eventType = r.uint8();
202Ôćĺ  const paramCount = r.uint8();
203Ôćĺ  const params: string[] = [];
204Ôćĺ  for (let i = 0; i < paramCount; i++) {
205Ôćĺ    params.push(r.cString());
206Ôćĺ  }
207Ôćĺ  if (HAS_TRAILING_GUID.has(eventType as any)) {
208Ôćĺ    r.uint64LE();
209Ôćĺ  }
210Ôćĺ  return { eventType, params };
211Ôćĺ}
212Ôćĺ```
213Ôćĺ
214ÔćĺNote: The `as any` cast is needed because `eventType` is `number` while the Set contains literal values. This is the simplest approach ÔÇö the set membership check works at runtime regardless.
