```ts
export const GuildEventCode = {
  PROMOTION: 0,
  DEMOTION: 1,
  MOTD: 2,
  JOINED: 3,
  LEFT: 4,
  REMOVED: 5,
  LEADER_IS: 6,
  LEADER_CHANGED: 7,
  DISBANDED: 8,
  SIGNED_ON: 12,
  SIGNED_OFF: 13,
} as const;

const HAS_TRAILING_GUID = new Set([
  GuildEventCode.JOINED,
  GuildEventCode.LEFT,
  GuildEventCode.SIGNED_ON,
  GuildEventCode.SIGNED_OFF,
]);

export type GuildEventRaw = {
  eventType: number;
  params: string[];
};

export function parseGuildEvent(r: PacketReader): GuildEventRaw {
  const eventType = r.uint8();
  const paramCount = r.uint8();
  const params: string[] = [];
  for (let i = 0; i < paramCount; i++) {
    params.push(r.cString());
  }
  if (HAS_TRAILING_GUID.has(eventType as any)) {
    r.uint64LE();
  }
  return { eventType, params };
}
```

Note: The `as any` cast is needed because `eventType` is `number` while the Set contains literal values. This is the simplest approach ÔÇö the set membership check works at runtime regardless.

