        w.uint8(9);
        w.uint8(0);
        ws.inject(GameOpcode.SMSG_GUILD_EVENT, w.finish());

        await Bun.sleep(50);
        expect(events).toHaveLength(0);

        handle.close();
        await handle.closed;
      } finally {
        ws.stop();
      }
    });
  });
});

