340Ôćĺ   340Ôćĺ+} as const;
341Ôćĺ   341Ôćĺ+
342Ôćĺ   342Ôćĺ+const HAS_TRAILING_GUID = new Set([
343Ôćĺ   343Ôćĺ+  GuildEventCode.JOINED,
344Ôćĺ   344Ôćĺ+  GuildEventCode.LEFT,
345Ôćĺ   345Ôćĺ+  GuildEventCode.SIGNED_ON,
