353Ôćĺ   353Ôćĺ+
354Ôćĺ   354Ôćĺ+export function parseGuildEvent(r: PacketReader): GuildEventRaw {
355Ôćĺ   355Ôćĺ+  const eventType = r.uint8();
356Ôćĺ   356Ôćĺ+  const paramCount = r.uint8();
357Ôćĺ   357Ôćĺ+  const params: string[] = [];
358Ôćĺ   358Ôćĺ+  for (let i = 0; i < paramCount; i++) {
359Ôćĺ   359Ôćĺ+    params.push(r.cString());
360Ôćĺ   360Ôćĺ+  }
361Ôćĺ   361Ôćĺ+  if (HAS_TRAILING_GUID.has(eventType as any)) {
362Ôćĺ   362Ôćĺ+    r.uint64LE();
363Ôćĺ   363Ôćĺ+  }
364Ôćĺ   364Ôćĺ+  return { eventType, params };
