      },
    });
    const lines = await sendToSocket("READ", sockPath);
    expect(lines[0]).toContain("Arthas");
  });

  test("onIgnoreEvent wiring pushes to ring buffer", async () => {
    startTestServer();
    handle.triggerIgnoreEvent({
      type: "ignore-added",
