    const e = fireEvent(5, ["Garrosh", "Thrall"]);
    expect(e).toEqual({ type: "removed", member: "Garrosh", officer: "Thrall" });
  });

  test("leader_is", () => {
    const e = fireEvent(6, ["Thrall"]);
    expect(e).toEqual({ type: "leader_is", name: "Thrall" });
