  test("disbanded", () => {
    const e = fireEvent(8, []);
    expect(e).toEqual({ type: "disbanded" });
  });

  test("signed_off", () => {
    const e = fireEvent(13, ["Varian"], 55n);
    expect(e).toEqual({ type: "signed_off", name: "Varian" });
  });
